/** TCP-based "ping": tries to open a socket to host:80 within `timeout` ms */
function tcpPing(host, port = 80, timeout = 4000) {
  return new Promise((resolve) => {
    const start  = Date.now();
    const socket = new net.Socket();

    socket.setTimeout(timeout);

    socket.on('connect', () => {
      const rtt = Date.now() - start;
      socket.destroy();
      resolve({ reachable: true, rtt, error: null });
    });

    const fail = (err) => {
      socket.destroy();
      resolve({ reachable: false, rtt: null, error: err.message || String(err) });
    };

    socket.on('timeout', () => fail(new Error('Connection timed out')));
    socket.on('error',   fail);
    socket.connect(port, host);
  });
}

/** Resolve A + AAAA records for a domain; returns arrays of addresses */
async function resolveDomain(domain) {
  const result = { domain, ipv4: [], ipv6: [], cname: null, error: null };
  try {
    result.ipv4 = await dns.resolve4(domain).catch(() => []);
    result.ipv6 = await dns.resolve6(domain).catch(() => []);
    if (result.ipv4.length === 0 && result.ipv6.length === 0) {
      // fall back to generic lookup
      const addrs = await dns.lookup(domain, { all: true });
      addrs.forEach(a => (a.family === 4 ? result.ipv4 : result.ipv6).push(a.address));
    }
  } catch (e) {
    result.error = e.message;
  }
  return result;
}

